bool 
tlBillboardDisplayInfoChunk::SetFieldValue(int fieldIndex, const char* new_val)
{
    switch(fieldIndex)
    {
        case 0:
        {
            char* end_ptr;
            unsigned long tmp;
            tmp = (unsigned long)strtoul(new_val, &end_ptr, 0);
            if (*end_ptr == 0)
            {
                version = tmp;
                return true;
            }
            return false;
        }
        case 1:
            return rotation.SetFieldValue(new_val);
        case 2:
        {
            cutoffmode = (unsigned long) tlFourCC(new_val);
            return true;
        }
        case 3:
            return uvoffsetrange.SetFieldValue(new_val);
        case 4:
        {
            char* end_ptr;
            float tmp;
            tmp = (float)strtod(new_val, &end_ptr);
            if (*end_ptr == 0)
            {
                sourcerange = tmp;
                return true;
            }
            return false;
        }
        case 5:
        {
            char* end_ptr;
            float tmp;
            tmp = (float)strtod(new_val, &end_ptr);
            if (*end_ptr == 0)
            {
                edgerange = tmp;
                return true;
            }
            return false;
        }
        default:
            return false;
    }
}

