int tlBillboardPerspectiveInfoChunk::sortPriority = -1;

tlBillboardPerspectiveInfoChunk::tlBillboardPerspectiveInfoChunk()
{
    Init();
}

tlBillboardPerspectiveInfoChunk::tlBillboardPerspectiveInfoChunk(const tlBillboardPerspectiveInfoChunk& ch)
{
    Init();
    *this = ch;
}

tlBillboardPerspectiveInfoChunk::~tlBillboardPerspectiveInfoChunk()
{

}

tlBillboardPerspectiveInfoChunk::tlBillboardPerspectiveInfoChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::BillboardObject::PERSPECTIVE_INFO);
    ident = Pure3D::BillboardObject::PERSPECTIVE_INFO;

    tlFile* f = ch->GetFile();

    version = f->GetLong();
    perspective = f->GetLong();
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::BillboardObject::PERSPECTIVE_INFO);
    }
}

void
tlBillboardPerspectiveInfoChunk::Init()
{
    ident = Pure3D::BillboardObject::PERSPECTIVE_INFO;
    version = 0;
    perspective = 0;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::BillboardObject::PERSPECTIVE_INFO);
    }
}

long 
tlBillboardPerspectiveInfoChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( version );
    s += sizeof( perspective );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlBillboardPerspectiveInfoChunk&
tlBillboardPerspectiveInfoChunk::operator=(const tlBillboardPerspectiveInfoChunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    version = a.version;
    perspective = a.perspective;

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlBillboardPerspectiveInfoChunk::operator==(const tlDataChunk& a)
{

    const tlBillboardPerspectiveInfoChunk* aptr = dynamic_cast<const tlBillboardPerspectiveInfoChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(version == aptr->version))
    {
        return false;
    }
    if(!(perspective == aptr->perspective))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlBillboardPerspectiveInfoChunk::NameCompare(const tlDataChunk& a)
{

    // This chunk has no name, so we must compare the bits
    return operator==(a);
}


