void
tlBillboardPerspectiveInfoChunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

        f->PutLong(version);
        f->PutLong(perspective);

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

