int tlBillboardQuadChunk::sortPriority = -1;

tlBillboardQuadChunk::tlBillboardQuadChunk()
{
    Init();
}

tlBillboardQuadChunk::tlBillboardQuadChunk(const tlBillboardQuadChunk& ch)
{
    Init();
    *this = ch;
}

tlBillboardQuadChunk::~tlBillboardQuadChunk()
{

    if(name != NULL){
        strdelete(name);
    }
}

tlBillboardQuadChunk::tlBillboardQuadChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::BillboardObject::QUAD);
    ident = Pure3D::BillboardObject::QUAD;

    tlFile* f = ch->GetFile();
    char buf[P3DMAXNAME];

    version = f->GetLong();
    f->GetPString(buf);
    name = strnew(buf);
    billboardmode = f->GetLong();
    translation.Read(f);
    colour = f->GetLong();
    uv0.Read(f);
    uv1.Read(f);
    uv2.Read(f);
    uv3.Read(f);
    width = f->GetFloat();
    height = f->GetFloat();
    distance = f->GetFloat();
    uvoffset.Read(f);
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::BillboardObject::QUAD);
    }
}

void
tlBillboardQuadChunk::Init()
{
    ident = Pure3D::BillboardObject::QUAD;
    version = 0;
    name = NULL;
    billboardmode = 0;
    translation.Init( );
    colour = 0;
    uv0.Init( );
    uv1.Init( );
    uv2.Init( );
    uv3.Init( );
    width = 0.0f;
    height = 0.0f;
    distance = 0.0f;
    uvoffset.Init( );
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::BillboardObject::QUAD);
    }
}

long 
tlBillboardQuadChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( version );
    s += strlen( name );
    s += sizeof( billboardmode );
    s += sizeof( translation );
    s += sizeof( colour );
    s += sizeof( uv0 );
    s += sizeof( uv1 );
    s += sizeof( uv2 );
    s += sizeof( uv3 );
    s += sizeof( width );
    s += sizeof( height );
    s += sizeof( distance );
    s += sizeof( uvoffset );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlBillboardQuadChunk&
tlBillboardQuadChunk::operator=(const tlBillboardQuadChunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    version = a.version;
    name = strnew(a.name);
    billboardmode = a.billboardmode;
    translation = a.translation;
    colour = a.colour;
    uv0 = a.uv0;
    uv1 = a.uv1;
    uv2 = a.uv2;
    uv3 = a.uv3;
    width = a.width;
    height = a.height;
    distance = a.distance;
    uvoffset = a.uvoffset;

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

