tlDataChunk*
tlBillboardQuadChunk::LoadSubChunk(tlFile* f)
{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case Pure3D::BillboardObject::DISPLAY_INFO:
        dch = new tlBillboardDisplayInfoChunk(&ch);
        break;
    case Pure3D::BillboardObject::PERSPECTIVE_INFO:
        dch = new tlBillboardPerspectiveInfoChunk(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

