// tlBillboardQuadGroupChunk

int tlBillboardQuadGroupChunk::sortPriority = -1;

tlBillboardQuadGroupChunk::tlBillboardQuadGroupChunk()
{
    Init();
}

tlBillboardQuadGroupChunk::tlBillboardQuadGroupChunk(const tlBillboardQuadGroupChunk& ch)
{
    Init();
    *this = ch;
}

tlBillboardQuadGroupChunk::~tlBillboardQuadGroupChunk()
{

    if(name != NULL){
        strdelete(name);
    }
    if(shader != NULL){
        strdelete(shader);
    }
}

tlBillboardQuadGroupChunk::tlBillboardQuadGroupChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::BillboardObject::QUAD_GROUP);
    ident = Pure3D::BillboardObject::QUAD_GROUP;

    tlFile* f = ch->GetFile();
    char buf[P3DMAXNAME];

    version = f->GetLong();
    f->GetPString(buf);
    name = strnew(buf);
    f->GetPString(buf);
    shader = strnew(buf);
    ztest = f->GetLong();
    zwrite = f->GetLong();
    fog = f->GetLong();
    numquads = f->GetLong();
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::BillboardObject::QUAD_GROUP);
    }
}

void
tlBillboardQuadGroupChunk::Init()
{
    ident = Pure3D::BillboardObject::QUAD_GROUP;
    version = 0;
    name = NULL;
    shader = NULL;
    ztest = 0;
    zwrite = 0;
    fog = 0;
    numquads = 0;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::BillboardObject::QUAD_GROUP);
    }
}

long 
tlBillboardQuadGroupChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( version );
    s += strlen( name );
    s += strlen( shader );
    s += sizeof( ztest );
    s += sizeof( zwrite );
    s += sizeof( fog );
    s += sizeof( numquads );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlBillboardQuadGroupChunk&
tlBillboardQuadGroupChunk::operator=(const tlBillboardQuadGroupChunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    version = a.version;
    name = strnew(a.name);
    shader = strnew(a.shader);
    ztest = a.ztest;
    zwrite = a.zwrite;
    fog = a.fog;
    numquads = a.numquads;

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlBillboardQuadGroupChunk::operator==(const tlDataChunk& a)
{

    const tlBillboardQuadGroupChunk* aptr = dynamic_cast<const tlBillboardQuadGroupChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(version == aptr->version))
    {
        return false;
    }
    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    if(strcmp(shader, aptr->shader) != 0)
    {
        return false;
    }
    if(!(ztest == aptr->ztest))
    {
        return false;
    }
    if(!(zwrite == aptr->zwrite))
    {
        return false;
    }
    if(!(fog == aptr->fog))
    {
        return false;
    }
    if(!(numquads == aptr->numquads))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlBillboardQuadGroupChunk::NameCompare(const tlDataChunk& a)
{

    const tlBillboardQuadGroupChunk* aptr = dynamic_cast<const tlBillboardQuadGroupChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }

    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    return true;
}


tlDataChunk*
tlBillboardQuadGroupChunk::Create(tlReadChunk16* ch)
{
    tlDataChunk* dtCh = new tlBillboardQuadGroupChunk(ch);
    return dtCh;
}

void
tlBillboardQuadGroupChunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

        f->PutLong(version);
        f->PutPString(name);
        f->PutPString(shader);
        f->PutLong(ztest);
        f->PutLong(zwrite);
        f->PutLong(fog);
        f->PutLong(numquads);

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlBillboardQuadGroupChunk::Print(int indent, unsigned int printdepth, unsigned int typemask)
{

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlBillboardQuadGroupChunk (%4x)\n",indent,"",(int) ident);
    printf("%*s  Version  = %ld\n",indent,"",version);
    printf("%*s  Name     = \"%s\"\n",indent,"",name);
    printf("%*s  Shader   = \"%s\"\n",indent,"",shader);
    printf("%*s  ZTest    = %ld\n",indent,"",ztest);
    printf("%*s  ZWrite   = %ld\n",indent,"",zwrite);
    printf("%*s  Fog      = %ld\n",indent,"",fog);
    printf("%*s  NumQuads = %ld\n",indent,"",numquads);

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

void
tlBillboardQuadGroupChunk::PrintFormatted(int indent)
{
    printf("%*schunk 0x%04x  \n",indent,"",(int) ident);
    printf("%*s  int   %12ld # Version \n",indent,"",version);
    printf("%*s  pstring \"%s\" # Name    \n",indent,"",name);
    printf("%*s  pstring \"%s\" # Shader  \n",indent,"",shader);
    printf("%*s  int   %12ld # ZTest   \n",indent,"",ztest);
    printf("%*s  int   %12ld # ZWrite  \n",indent,"",zwrite);
    printf("%*s  int   %12ld # Fog     \n",indent,"",fog);
    printf("%*s  int   %12ld # NumQuads\n",indent,"",numquads);
    if(subcount)
    {
        for(int i=0;i<subcount;i++)
        {
            GetSubChunk(i)->PrintFormatted(indent+2);
        }
    }
    printf("%*sendchunk\n",indent,"");
}

